rows.customCode:
(() => {
  'use strict';
  if (window.__pcbw_companionInit) return;
  window.__pcbw_companionInit = true;

  const NS = '__pcbw_companion';
  const MODES = ['casual', 'focused', 'creative', 'supportive'];

  function ensureState() {
    if (!oc.thread.customData) oc.thread.customData = {};
    if (!oc.thread.customData[NS]) {
      oc.thread.customData[NS] = {
        mode: 'casual',
        moodHistory: [],
        interactionCount: 0,
        topicsDiscussed: [],
        companionLevel: 1,
        lastModeChange: Date.now(),
        preferences: {}
      };
    }
    return oc.thread.customData[NS];
  }

  function detectModeSwitch(text) {
    const lower = (text || '').toLowerCase().trim();
    if (lower.startsWith('/mode ')) {
      const requested = lower.replace('/mode ', '').trim();
      if (MODES.includes(requested)) return requested;
    }
    if (lower === '/status') return '__status__';
    return null;
  }

  function updateCompanionLevel(state) {
    const count = state.interactionCount;
    if (count >= 50) state.companionLevel = 5;
    else if (count >= 30) state.companionLevel = 4;
    else if (count >= 15) state.companionLevel = 3;
    else if (count >= 5) state.companionLevel = 2;
    else state.companionLevel = 1;
  }

  function buildContextHint(state) {
    const hints = [];
    hints.push('[Companion State: mode=' + state.mode + ', level=' + state.companionLevel + ', interactions=' + state.interactionCount + ']');
    if (state.topicsDiscussed.length > 0) {
      hints.push('[Recent topics: ' + state.topicsDiscussed.slice(-3).join(', ') + ']');
    }
    return hints.join('\n');
  }

  oc.thread.on('MessageAdded', function() {
    try {
      const state = ensureState();
      const msgs = oc.thread.messages;
      if (!msgs || msgs.length === 0) return;

      const last = msgs[msgs.length - 1];
      if (last.author !== 'user') return;

      state.interactionCount++;
      updateCompanionLevel(state);

      const text = (last.content || '').trim();
      const modeSwitch = detectModeSwitch(text);

      if (modeSwitch === '__status__') {
        return;
      } else if (modeSwitch) {
        state.mode = modeSwitch;
        state.lastModeChange = Date.now();
        state.moodHistory.push({ mode: modeSwitch, at: Date.now() });
        if (state.moodHistory.length > 20) state.moodHistory = state.moodHistory.slice(-20);
      }

      if (text.length > 10 && !text.startsWith('/')) {
        const topic = text.substring(0, 80);
        state.topicsDiscussed.push(topic);
        if (state.topicsDiscussed.length > 10) {
          state.topicsDiscussed = state.topicsDiscussed.slice(-10);
        }
      }

      const contextHint = buildContextHint(state);
      if (oc.character && oc.character.reminderMessage !== undefined) {
        const baseReminder = 'Adapt your tone and style to your current mode. casual=relaxed and friendly, focused=precise and efficient, creative=imaginative and expressive, supportive=warm and encouraging. Show awareness of conversation history and relationship depth.';
        oc.character.reminderMessage = baseReminder + '\n' + contextHint;
      }
    } catch (e) {
      console.warn('[CompanionBot] MessageAdded handler error:', e);
    }
  });
})();
